SELECT name, average_resolution_time
FROM institutions
WHERE consumer_satisfaction_score = (SELECT MAX(consumer_satisfaction_score) FROM institutions);

SELECT name, total_complaints
FROM institutions
ORDER BY total_complaints DESC;

SELECT AVG(resolution_time_days) AS average_resolution_time
FROM complaints
WHERE monetary_relief = 1;

SELECT name, total_complaints
FROM institutions
ORDER BY total_complaints DESC;

SELECT name
FROM institutions
WHERE average_resolution_time > (SELECT AVG(average_resolution_time) FROM institutions);

SELECT complaint_id
FROM complaints
WHERE complaint_id = 1;

SELECT AVG(resolution_time_days) AS average_resolution_time
FROM complaints
WHERE date_received BETWEEN '2023-01-01' AND '2023-12-31';

SELECT name, consumer_satisfaction_score
FROM institutions
ORDER BY consumer_satisfaction_score DESC;
